"use client";
import React, { useState } from 'react'

const ERROR_IMG_SRC =
  'data:image/svg+xml;base64,'

type ImageSrc = string | { src: string; width?: number; height?: number };

interface ImageWithFallbackProps extends Omit<React.ImgHTMLAttributes<HTMLImageElement>, 'src'> {
  src?: ImageSrc;
}

function resolveSrc(src?: ImageSrc): string | undefined {
  if (!src) return undefined;
  if (typeof src === "string") return src;
  return src.src;
}

export function ImageWithFallback(props: ImageWithFallbackProps) {
  const [didError, setDidError] = useState(false)

  const handleError = () => {
    setDidError(true)
  }

  const { src: rawSrc, alt, style, className, loading, ...rest } = props
  const src = resolveSrc(rawSrc);

  return didError ? (
    <div
      className={`inline-block bg-gray-100 text-center align-middle ${className ?? ''}`}
      style={style}
    >
      <div className="flex items-center justify-center w-full h-full">
        <img src={ERROR_IMG_SRC} alt="Error loading image" {...rest} data-original-url={src} />
      </div>
    </div>
  ) : (
    <img src={src} alt={alt} className={className} style={style} loading={loading ?? "lazy"} {...rest} onError={handleError} />
  )
}
